  },

  // Public endpoints - very generous
  public: {
    default: { limit: 10000, window: 3600 }, // 10000 per hour
  },
};

/**
 * Apply rate limiting to route
 */
export function applyRateLimit(
  request: FastifyRequest,
  config: { limit: number; window: number }
) {
  return createRateLimiter(config);
}

/**
 * Get rate limit status for key
 */
export function getRateLimitStatus(key: string, limit: number) {
  const entry = globalStore.get(key);

  if (!entry) {
    return {
      count: 0,
      limit,
      remaining: limit,
      resetTime: Date.now() + 3600000,
      isLimited: false,
    };
  }

  return {
    count: entry.count,
    limit,
    remaining: Math.max(0, limit - entry.count),
    resetTime: entry.resetTime,
    isLimited: entry.count >= limit,
  };
}

/**
 * Reset rate limit for key
 */
export function resetRateLimit(key: string) {
  globalStore.reset(key);
}

/**
 * Cleanup rate limiter
 */
export function cleanupRateLimiter() {
  globalStore.destroy();
}

/**
 * Rate limit middleware factory
 */
export function createRateLimitMiddleware(
  limitConfig: Record<string, { limit: number; window: number }>
) {
  return async (request: FastifyRequest, reply: FastifyReply) => {
    // Determine which config to use based on route
    let config = limitConfig['default'];

    for (const [pattern, cfg] of Object.entries(limitConfig)) {
      if (pattern !== 'default' && request.url.includes(pattern)) {
        config = cfg;
        break;
      }
    }

    if (config) {
      await createRateLimiter({
        limit: config.limit,
        window: config.window,
        keyGenerator: (req) => `${req.method}:${req.url}:${req.ip}`,
      })(request, reply);
    }
  };
}

/**
 * Scraper Source Service
 * Manages scraper sources (CRUD operations, validation, statistics)
 */

import { prisma } from '@audira/database';
import { logger } from './loggerService';
import { createAppError } from '../middleware/errorHandler';
import { ErrorCode } from '../constants/errorCodes';

/**
 * Scraper Source Interface
 */
export interface ScraperSource {
  id: string;
  name: string;
  url: string;
  type: 'ANIME' | 'MANGA' | 'DONGHUA';
  selector: string;
  headers?: Record<string, string>;
  proxy?: string;
  timeout: number;
  retryCount: number;
  retryDelay: number;
  rateLimit: number;
  enabled: boolean;
  lastRun?: Date;
  lastError?: string;
  successCount: number;
  failureCount: number;
  createdAt: Date;
  updatedAt: Date;
}

/**
 * Scraper Source Service
 */
export class ScraperSourceService {
  /**
   * Create new scraper source
   */
  async createSource(data: {
    name: string;
    url: string;
    type: 'ANIME' | 'MANGA' | 'DONGHUA';
    selector: string;
    headers?: Record<string, string>;
    proxy?: string;
    timeout?: number;
    retryCount?: number;
    retryDelay?: number;
    rateLimit?: number;
  }): Promise<ScraperSource> {
    try {
      // Validate input
      this.validateSourceData(data);

      // Check if source with same URL already exists
      const existing = await prisma.scraperSource.findUnique({
        where: { url: data.url },
      });

      if (existing) {
        throw createAppError(
          'Scraper source dengan URL ini sudah ada',
          ErrorCode.SCRAPER_INVALID_CONFIG,
          400
        );
      }

      // Create source
      const source = await prisma.scraperSource.create({
        data: {
          name: data.name,
          url: data.url,
          type: data.type,
          selector: data.selector,
          headers: data.headers,
          proxy: data.proxy,
          timeout: data.timeout || 30000,
          retryCount: data.retryCount || 3,
          retryDelay: data.retryDelay || 1000,
          rateLimit: data.rateLimit || 10,
          enabled: true,
          successCount: 0,
          failureCount: 0,
        },
      });

      logger.info('Scraper source created', {
        sourceId: source.id,
        name: source.name,
        type: source.type,
      });

      return source as ScraperSource;
    } catch (error) {
      logger.error('Failed to create scraper source', error as Error, {
        data,
      });
      throw error;
    }
  }

  /**
   * Update scraper source
   */
  async updateSource(
    id: string,
    data: Partial<{
      name: string;
      url: string;
      selector: string;
      headers: Record<string, string>;
      proxy: string;
      timeout: number;
      retryCount: number;
      retryDelay: number;
      rateLimit: number;
      enabled: boolean;
    }>
  ): Promise<ScraperSource> {
    try {
      // Check if source exists
      const source = await prisma.scraperSource.findUnique({
        where: { id },
      });

      if (!source) {
        throw createAppError(
          'Scraper source tidak ditemukan',
          ErrorCode.SCRAPER_SOURCE_NOT_FOUND,
          404
        );
      }

      // Validate input if provided
      if (data) {
        this.validateSourceData(data);
      }

      // Check if new URL already exists (if URL is being changed)
      if (data.url && data.url !== source.url) {
        const existing = await prisma.scraperSource.findUnique({
          where: { url: data.url },
        });

        if (existing) {
          throw createAppError(
            'Scraper source dengan URL ini sudah ada',
            ErrorCode.SCRAPER_INVALID_CONFIG,
            400
          );
        }
      }

      // Update source
      const updated = await prisma.scraperSource.update({
        where: { id },
        data,
      });

      logger.info('Scraper source updated', {
        sourceId: id,
        changes: Object.keys(data),
      });

      return updated as ScraperSource;
    } catch (error) {
      logger.error('Failed to update scraper source', error as Error, {
        id,
        data,
      });
      throw error;
    }
  }

  /**
   * Delete scraper source
   */
  async deleteSource(id: string): Promise<void> {
    try {
      // Check if source exists
      const source = await prisma.scraperSource.findUnique({
        where: { id },
      });

      if (!source) {
        throw createAppError(
          'Scraper source tidak ditemukan',
          ErrorCode.SCRAPER_SOURCE_NOT_FOUND,
          404
        );
      }

      // Delete source
      await prisma.scraperSource.delete({
        where: { id },
      });

      logger.info('Scraper source deleted', {
        sourceId: id,
        name: source.name,
      });
    } catch (error) {
      logger.error('Failed to delete scraper source', error as Error, {
        id,
      });
      throw error;
    }
  }

  /**
   * Get single scraper source
   */
  async getSource(id: string): Promise<ScraperSource> {
    try {
      const source = await prisma.scraperSource.findUnique({
        where: { id },
      });

      if (!source) {
        throw createAppError(
          'Scraper source tidak ditemukan',
          ErrorCode.SCRAPER_SOURCE_NOT_FOUND,
          404
        );
      }

      return source as ScraperSource;
    } catch (error) {
      logger.error('Failed to get scraper source', error as Error, { id });
      throw error;
    }
  }

  /**
   * List scraper sources with pagination
   */
  async listSources(filters: {
    page?: number;
    limit?: number;
    type?: 'ANIME' | 'MANGA' | 'DONGHUA';
    enabled?: boolean;
    search?: string;
  }): Promise<{ sources: ScraperSource[]; total: number }> {
    try {
      const page = filters.page || 1;
      const limit = filters.limit || 10;
      const skip = (page - 1) * limit;

      // Build where clause
      const where: any = {};

      if (filters.type) {
        where.type = filters.type;
      }

      if (filters.enabled !== undefined) {
        where.enabled = filters.enabled;
      }

      if (filters.search) {
        where.OR = [
          { name: { contains: filters.search, mode: 'insensitive' } },
          { url: { contains: filters.search, mode: 'insensitive' } },
        ];
      }

      // Get total count
      const total = await prisma.scraperSource.count({ where });

      // Get sources
      const sources = await prisma.scraperSource.findMany({
        where,
        skip,
        take: limit,
        orderBy: { createdAt: 'desc' },
      });

      return {
        sources: sources as ScraperSource[],
        total,
      };
    } catch (error) {
      logger.error('Failed to list scraper sources', error as Error, {
        filters,
      });
      throw error;
    }
  }

  /**
   * Get scraper source statistics
   */
  async getSourceStats(id: string): Promise<{
    id: string;
    name: string;
    successCount: number;
    failureCount: number;
    successRate: number;
    lastRun?: Date;
    lastError?: string;
  }> {
    try {
      const source = await prisma.scraperSource.findUnique({
        where: { id },
      });

      if (!source) {
        throw createAppError(
          'Scraper source tidak ditemukan',
          ErrorCode.SCRAPER_SOURCE_NOT_FOUND,
          404
        );
      }

      const total = source.successCount + source.failureCount;
      const successRate = total > 0 ? (source.successCount / total) * 100 : 0;

      return {
        id: source.id,
        name: source.name,
        successCount: source.successCount,
        failureCount: source.failureCount,
        successRate: Math.round(successRate * 100) / 100,
        lastRun: source.lastRun,
        lastError: source.lastError,
      };
    } catch (error) {
      logger.error('Failed to get scraper source stats', error as Error, {
        id,
      });
      throw error;
    }
  }

  /**
   * Validate scraper source data
   */
  private validateSourceData(data: any): void {
    // Validate name
    if (data.name && (typeof data.name !== 'string' || data.name.length === 0)) {
      throw createAppError(
        'Nama scraper harus berupa string non-kosong',
        ErrorCode.SCRAPER_INVALID_CONFIG,
        400
      );
    }

    // Validate URL
    if (data.url) {
      try {
        new URL(data.url);
      } catch {
        throw createAppError(
          'URL tidak valid',
          ErrorCode.SCRAPER_INVALID_CONFIG,
          400
        );
      }
    }

    // Validate type
    if (data.type && !['ANIME', 'MANGA', 'DONGHUA'].includes(data.type)) {
      throw createAppError(
        'Type harus salah satu dari: ANIME, MANGA, DONGHUA',
        ErrorCode.SCRAPER_INVALID_CONFIG,
        400
      );
    }

    // Validate selector
    if (data.selector && (typeof data.selector !== 'string' || data.selector.length === 0)) {
      throw createAppError(
        'CSS selector harus berupa string non-kosong',
        ErrorCode.SCRAPER_INVALID_CONFIG,
        400
      );
    }

    // Validate timeout
    if (data.timeout && (typeof data.timeout !== 'number' || data.timeout < 1000)) {
      throw createAppError(
        'Timeout harus berupa number >= 1000',
        ErrorCode.SCRAPER_INVALID_CONFIG,
        400
      );
    }

    // Validate retry count
    if (data.retryCount && (typeof data.retryCount !== 'number' || data.retryCount < 0)) {
      throw createAppError(
        'Retry count harus berupa number >= 0',
        ErrorCode.SCRAPER_INVALID_CONFIG,
        400
      );
    }

    // Validate rate limit
    if (data.rateLimit && (typeof data.rateLimit !== 'number' || data.rateLimit < 1)) {
      throw createAppError(
        'Rate limit harus berupa number >= 1',
        ErrorCode.SCRAPER_INVALID_CONFIG,
        400
      );
    }

    // Validate proxy if provided
    if (data.proxy) {
      try {
        new URL(data.proxy);
      } catch {
        throw createAppError(
          'Proxy URL tidak valid',
          ErrorCode.SCRAPER_INVALID_CONFIG,
          400
        );
      }
    }
  }

  /**
   * Test scraper source connectivity
   */
  async testSource(id: string): Promise<{
    success: boolean;
    message: string;
    responseTime?: number;
    error?: string;
  }> {
    try {
      const source = await this.getSource(id);

      const startTime = Date.now();

      try {
        // Simple connectivity test
        const response = await fetch(source.url, {
          method: 'GET',
          timeout: source.timeout,
          headers: source.headers || {},
        });

        const responseTime = Date.now() - startTime;

        if (response.ok) {
          logger.info('Scraper source test successful', {
            sourceId: id,
            responseTime,
            statusCode: response.status,
          });

          return {
            success: true,
            message: 'Koneksi berhasil',
            responseTime,
          };
        } else {
          return {
            success: false,
            message: `HTTP ${response.status}`,
            error: `Server returned status ${response.status}`,
          };
        }
      } catch (error) {
        const responseTime = Date.now() - startTime;

        logger.warn('Scraper source test failed', {
          sourceId: id,
          responseTime,
          error: error instanceof Error ? error.message : String(error),
        });

        return {
          success: false,
          message: 'Koneksi gagal',
          responseTime,
          error: error instanceof Error ? error.message : String(error),
        };
      }
    } catch (error) {
      logger.error('Failed to test scraper source', error as Error, { id });
      throw error;
    }
  }

  /**
   * Update source statistics
   */
  async updateStats(
    id: string,
    success: boolean,
    error?: string
  ): Promise<void> {
    try {
      const source = await prisma.scraperSource.findUnique({
        where: { id },
      });

      if (!source) {
        throw createAppError(
          'Scraper source tidak ditemukan',
          ErrorCode.SCRAPER_SOURCE_NOT_FOUND,
          404
        );
      }

      await prisma.scraperSource.update({
        where: { id },
        data: {
          successCount: success ? source.successCount + 1 : source.successCount,
          failureCount: !success ? source.failureCount + 1 : source.failureCount,
          lastRun: new Date(),
          lastError: error,
        },
      });
    } catch (error) {
      logger.error('Failed to update scraper source stats', error as Error, {
        id,
        success,
      });
      throw error;
    }
  }

  /**
   * Get all enabled sources
   */
  async getEnabledSources(): Promise<ScraperSource[]> {
    try {
      const sources = await prisma.scraperSource.findMany({
        where: { enabled: true },
        orderBy: { createdAt: 'asc' },
      });

      return sources as ScraperSource[];
    } catch (error) {
      logger.error('Failed to get enabled scraper sources', error as Error);
      throw error;
    }
  }
}

